type FieldDef = {
  name: string; label: string; type?: 'number' | 'text' | 'select' | 'date'
  min?: number; max?: number; step?: number | string; placeholder?: string; unit?: string
  options?: { label: string; value: string }[]
}

type ResultValue = { result: number | string; label: string; unit: string; steps?: (string | { label: string; value: string })[] }

type CalcDef = {
  schema: z.ZodObject<any, any, any>
  fields: FieldDef[]
  compute: (values: Record<string, unknown>) => ResultValue
  description: string
  formula: string
  interpretation: string
  presets?: { label: string; values: Record<string, string> }[]
}

function n(v: unknown): number {
  if (typeof v === 'number') return v
  const x = parseFloat(String(v ?? ''))
  return isNaN(x) ? 0 : x
}

function d(v: unknown): Date {
  const s = String(v ?? '')
  const parsed = new Date(s)
  return isNaN(parsed.getTime()) ? new Date() : parsed
}

function daysBetween(a: Date, b: Date): number {
  return Math.floor((b.getTime() - a.getTime()) / (1000 * 60 * 60 * 24))
}

const today = (): string => new Date().toISOString().split('T')[0]

function ymd(date: Date): string {
  return `${date.getFullYear()}-${(date.getMonth()+1).toString().padStart(2,'0')}-${date.getDate().toString().padStart(2,'0')}`
}

